1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	export interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	export interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	export type Step = QuoteStep | ClaimStep;
25	
26	export interface Scenario {
27	  customer: Customer;
28	  steps: Step[];
29	}
30	
31	type Customer = { yearsWithMHPCO: number };
32	
33	export interface QuoteResult { premium: number }
34	export interface ClaimResult { payout: number; remainingCap: number }
35	
36	export interface ScenarioResult {
37	  results: (QuoteResult | ClaimResult)[];
38	}
39	
40	const PROCESSING_FEE = 5;
41	
42	const BASE_PRICE_BY_TYPE: Record<string, number> = {
43	  sword: 100,
44	  amulet: 60,
45	  staff: 80,
46	  potion: 40,
47	  rune: 25,
48	  moonstone: 25,
49	};
50	
51	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	
63	const basePriceFor = (item: Item): number => {
64	  if (!(item.type in BASE_PRICE_BY_TYPE)) {
65	    throw new Error(`Unknown item type: ${item.type}`);
66	  }
67	  return BASE_PRICE_BY_TYPE[item.type];
68	};
69	
70	const COMPONENT_BLOCK_SIZE = 3;
71	const COMPONENT_BLOCK_PRICE = 60;
72	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
73	
74	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
75	
76	const sumBasePrices = (items: Item[]): number =>
77	  items.reduce((s, i) => s + basePriceFor(i), 0);
78	
79	const groupByType = (items: Item[]): Map<string, Item[]> => {
80	  const map = new Map<string, Item[]>();
81	  for (const item of items) {
82	    const list = map.get(item.type) ?? [];
83	    list.push(item);
84	    map.set(item.type, list);
85	  }
86	  return map;
87	};
88	
89	const priceForGroup = (group: Item[]): number =>
90	  isComponent(group[0]) && group.length === COMPONENT_BLOCK_SIZE
91	    ? COMPONENT_BLOCK_PRICE
92	    : sumBasePrices(group);
93	
94	const itemsBasePremium = (items: Item[]): number =>
95	  Array.from(groupByType(items).values())
96	    .reduce((sum, group) => sum + priceForGroup(group), 0);
97	
98	const CURSE_SURCHARGE_RATE = 0.5;
99	const HIGH_ENCHANTMENT_RATE = 0.3;
100	const HIGH_ENCHANTMENT_THRESHOLD = 5;
101	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
102	const LOYALTY_DISCOUNT_RATE = 0.2;
103	const LOYALTY_YEARS_THRESHOLD = 2;
104	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
105	
106	const perItemSurchargeRate = (item: Item): number =>
107	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
108	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0);
109	
110	const itemSurcharges = (items: Item[]): number =>
111	  items.reduce((sum, item) => sum + basePriceFor(item) * perItemSurchargeRate(item), 0);
112	
113	const isLoyal = (customer: Customer): boolean =>
114	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
115	
116	const loyaltyDiscountFor = (base: number, customer: Customer): number =>
117	  isLoyal(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
118	
119	const followUpDiscountFor = (base: number, isFollowUp: boolean): number =>
120	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
121	
122	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): number => {
123	  const base = itemsBasePremium(step.items);
124	  const total = base
125	    + itemSurcharges(step.items)
126	    + base * FIRST_INSURANCE_SURCHARGE_RATE
127	    - loyaltyDiscountFor(base, customer)
128	    - followUpDiscountFor(base, isFollowUp);
129	  return Math.ceil(total + PROCESSING_FEE);
130	};
131	
132	type Policy = { items: Item[]; remainingCap: number };
133	
134	const insuranceSum = (items: Item[]): number =>
135	  items.reduce((s, i) => s + INSURANCE_VALUE_BY_TYPE[i.type], 0);
136	
137	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
138	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
139	
140	const isHighlyEnchanted = (item: Item): boolean =>
141	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
142	
143	const claimableDamage = (damage: Damage, item: Item): number =>
144	  isHighlyEnchanted(item)
145	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
146	    : damage.amount;
147	
148	const reimbursableFor = (damage: Damage, item: Item): number =>
149	  Math.max(0, claimableDamage(damage, item) - DEDUCTIBLE);
150	
151	const findPolicyItem = (items: Item[], itemType: string): Item => {
152	  const item = items.find((i) => i.type === itemType);
153	  if (!item) throw new Error(`Item ${itemType} not in policy`);
154	  return item;
155	};
156	
157	const payoutForDamage = (damage: Damage, items: Item[]): number =>
158	  reimbursableFor(damage, findPolicyItem(items, damage.itemType));
159	
160	const totalPayoutWithinCap = (damages: Damage[], items: Item[], cap: number): number =>
161	  damages.reduce(
162	    (paid, damage) => paid + Math.min(payoutForDamage(damage, items), cap - paid),
163	    0,
164	  );
165	
166	const assertNonNegativeDamages = (damages: Damage[]): void => {
167	  const negative = damages.find((d) => d.amount < 0);
168	  if (negative) throw new Error(`Negative damage amount: ${negative.amount}`);
169	};
170	
171	const assertDamagesCoveredByPolicy = (damages: Damage[], items: Item[]): void => {
172	  const itemCounts = new Map<string, number>();
173	  for (const item of items) itemCounts.set(item.type, (itemCounts.get(item.type) ?? 0) + 1);
174	  const damageCounts = new Map<string, number>();
175	  for (const d of damages) damageCounts.set(d.itemType, (damageCounts.get(d.itemType) ?? 0) + 1);
176	  for (const [type, count] of damageCounts) {
177	    if (count > (itemCounts.get(type) ?? 0)) {
178	      throw new Error(`More ${type} damages than policy covers`);
179	    }
180	  }
181	};
182	
183	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
184	  assertNonNegativeDamages(step.incident.damages);
185	  const policy = policies[step.policy];
186	  assertDamagesCoveredByPolicy(step.incident.damages, policy.items);
187	  const payout = totalPayoutWithinCap(step.incident.damages, policy.items, policy.remainingCap);
188	  policy.remainingCap -= payout;
189	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
190	};
191	
192	const openPolicy = (items: Item[]): Policy => ({
193	  items,
194	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
195	});
196	
197	export const runScenario = (scenario: Scenario): ScenarioResult => {
198	  const policies: Policy[] = [];
199	  const results: (QuoteResult | ClaimResult)[] = [];
200	  scenario.steps.forEach((step, stepIndex) => {
201	    if (step.op === "quote") {
202	      const isFollowUp = stepIndex > 0;
203	      policies[stepIndex] = openPolicy(step.items);
204	      results.push({ premium: quotePremium(step, scenario.customer, isFollowUp) });
205	    } else {
206	      results.push(processClaim(step, policies));
207	    }
208	  });
209	  return { results };
210	};
